```lean
import Mathlib

theorem main_proof :
  ∀ n : Nat, (let n := n; let x := n; let y := 0; let z := 0;
    let x1 := x - 1; let y1 := y + 1;
    let x2 := x1 + 1; let z2 := z + 1;
    let y3 := y1 - 1; let z3 := z2 + 1;
    let x4 := x2 - 1; let y4 := y3 + 1;
    let x5 := x4 + 1; let z4 := z3 - 1;
    let y6 := y4 - 1; let z6 := z4 + 1;
    z6 = n) := by
  intro n
  simp
  omega
```
